/**
 * Unit tests for lifecycle/rules-size-check (#1815)
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { rulesSizeCheck, _internals } from '../lifecycle/rules-size-check.js';
import { NOOP_CTX } from '../lib/context.js';
import type { HookInput } from '../types.js';

describe('lifecycle/rules-size-check (#1815)', () => {
  let tmp: string;
  let stderrSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'rules-size-'));
    stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation(() => true);
  });

  afterEach(() => {
    stderrSpy.mockRestore();
    try { rmSync(tmp, { recursive: true, force: true }); } catch { /* best-effort */ }
  });

  const inputFor = (projectDir: string): HookInput => ({
    hook_event: 'SessionStart',
    tool_name: '',
    session_id: 'test-session-1815',
    tool_input: {},
    project_dir: projectDir,
  });

  function writeRule(name: string, sizeBytes: number) {
    const rulesDir = join(tmp, '.claude', 'rules');
    mkdirSync(rulesDir, { recursive: true });
    writeFileSync(join(rulesDir, name), 'x'.repeat(sizeBytes), 'utf8');
  }

  // ---- thresholds (sanity) ----
  it('exposes thresholds: WARN < CRITICAL < CC native 40k', () => {
    expect(_internals.WARN_THRESHOLD).toBeLessThan(_internals.CRITICAL_THRESHOLD);
    expect(_internals.CRITICAL_THRESHOLD).toBeLessThan(40_000);
    // Safety margin should be meaningful (≥ 5%).
    expect(40_000 - _internals.WARN_THRESHOLD).toBeGreaterThanOrEqual(2_000);
  });

  // ---- silent paths ----
  it('returns silent success when .claude/rules/ does not exist', () => {
    const result = rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('returns silent success when all rules files are under WARN threshold', () => {
    writeRule('small.md', 1_000);
    writeRule('medium.md', _internals.WARN_THRESHOLD - 1);
    const result = rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('returns silent success on missing project_dir', () => {
    const result = rulesSizeCheck(
      { hook_event: 'SessionStart', tool_name: '', session_id: 's', tool_input: {} },
      NOOP_CTX,
    );
    expect(result).toEqual({ continue: true, suppressOutput: true });
  });

  it('hook never throws on null/undefined/non-object input', () => {
    // @ts-expect-error — defensive
    expect(() => rulesSizeCheck(null, NOOP_CTX)).not.toThrow();
    // @ts-expect-error — defensive
    expect(() => rulesSizeCheck(undefined, NOOP_CTX)).not.toThrow();
    // @ts-expect-error — defensive
    expect(() => rulesSizeCheck('not an object', NOOP_CTX)).not.toThrow();
  });

  // ---- warning paths ----
  it('warns on a file at WARN threshold', () => {
    writeRule('recent-decisions.md', _internals.WARN_THRESHOLD + 100);
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    expect(stderrSpy).toHaveBeenCalledTimes(1);
    const call = stderrSpy.mock.calls[0][0] as string;
    expect(call).toContain('WARN');
    expect(call).toContain('recent-decisions.md');
    expect(call).toContain('storage-patterns');
    expect(call).toContain('CONTRIBUTING-SKILLS.md');
  });

  it('escalates to CRITICAL above CRITICAL threshold', () => {
    writeRule('huge.md', _internals.CRITICAL_THRESHOLD + 100);
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    const call = stderrSpy.mock.calls[0][0] as string;
    expect(call).toContain('CRITICAL');
    expect(call).toContain('huge.md');
  });

  it('emits one line per offender, sorted largest first', () => {
    writeRule('biggest.md', _internals.CRITICAL_THRESHOLD + 5_000);
    writeRule('medium-warn.md', _internals.WARN_THRESHOLD + 500);
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    const call = stderrSpy.mock.calls[0][0] as string;
    const lines = call.trim().split('\n');
    expect(lines).toHaveLength(2);
    expect(lines[0]).toContain('biggest.md');     // largest first
    expect(lines[1]).toContain('medium-warn.md');
  });

  it('only flags *.md files (ignores other extensions)', () => {
    const rulesDir = join(tmp, '.claude', 'rules');
    mkdirSync(rulesDir, { recursive: true });
    writeFileSync(join(rulesDir, 'huge.txt'), 'x'.repeat(_internals.CRITICAL_THRESHOLD + 1_000));
    writeFileSync(join(rulesDir, 'huge.json'), 'x'.repeat(_internals.CRITICAL_THRESHOLD + 1_000));
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('falls back to ctx.projectDir when input.project_dir is absent', () => {
    writeRule('ctx-test.md', _internals.WARN_THRESHOLD + 100);
    const input: HookInput = {
      hook_event: 'SessionStart',
      tool_name: '',
      session_id: 's',
      tool_input: {},
    };
    rulesSizeCheck(input, { ...NOOP_CTX, projectDir: tmp });
    expect(stderrSpy).toHaveBeenCalledTimes(1);
  });

  it('warning text includes size in KiB and char count', () => {
    writeRule('size-test.md', _internals.WARN_THRESHOLD + 1_000);
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    const call = stderrSpy.mock.calls[0][0] as string;
    expect(call).toMatch(/\d+\.\d KiB/);
    expect(call).toMatch(/\d{1,3}(,\d{3})* chars/);
  });

  it('warning text points to storage-patterns reference (#1816)', () => {
    writeRule('point.md', _internals.WARN_THRESHOLD + 100);
    rulesSizeCheck(inputFor(tmp), NOOP_CTX);
    const call = stderrSpy.mock.calls[0][0] as string;
    expect(call).toContain('storage-patterns');
    expect(call).toContain('CONTRIBUTING-SKILLS.md');
  });
});
